1	export function sanitizeUserInput(input: string): string {
2	  // biome-ignore lint/suspicious/noControlCharactersInRegex: 制御文字の除去はセキュリティ対策として意図的に実施（タブ・改行は除外）
3	  const controlCharRegex = /[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g;
4	  return input
5	    .replaceAll(controlCharRegex, "")
6	    .replaceAll("<", "&lt;")
7	    .replaceAll(">", "&gt;");
8	}
