"use client";

import { valibotResolver } from "@hookform/resolvers/valibot";
import { Button } from "@workspace/ui/components/button";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@workspace/ui/components/form";
import { Input } from "@workspace/ui/components/input";
import { Search } from "lucide-react";
import { useRouter } from "next/navigation";
import { useForm } from "react-hook-form";
import * as v from "valibot";
import { useIsHydrated } from "@/libs/use-is-hydrated.hook";
import {
  STAFF_SEARCH_KEYWORD_MAX_LENGTH,
  staffsConditionSchema,
} from "./schema";

const formSchema = v.omit(staffsConditionSchema, ["page"]);

export function StaffSearchForm({
  condition,
}: {
  condition: v.InferInput<typeof formSchema>;
}) {
  const router = useRouter();
  const { isHydrated } = useIsHydrated();

  const form = useForm<v.InferInput<typeof formSchema>>({
    defaultValues: { keyword: condition.keyword },
    resolver: valibotResolver(formSchema),
  });

  function onSubmit({ keyword }: v.InferOutput<typeof formSchema>) {
    const parameters = new URLSearchParams();
    if (keyword) {
      parameters.set("keyword", keyword);
    }

    router.push(`/staffs?${parameters}`);
  }

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)}>
        <FormField
          control={form.control}
          name="keyword"
          render={({ field }) => (
            <FormItem>
              <FormLabel>キーワード</FormLabel>
              <FormDescription>
                姓または名で完全一致検索（最大
                {STAFF_SEARCH_KEYWORD_MAX_LENGTH}文字）
              </FormDescription>
              <div className="flex items-center gap-4">
                <FormControl>
                  <Input
                    {...field}
                    disabled={!isHydrated}
                    maxLength={STAFF_SEARCH_KEYWORD_MAX_LENGTH}
                    type="text"
                  />
                </FormControl>
                <Button disabled={!isHydrated} type="submit">
                  <Search className="mr-2 h-4 w-4" />
                  検索
                </Button>
              </div>
              <FormMessage />
            </FormItem>
          )}
        />
      </form>
    </Form>
  );
}

