124	export function createServerAction<
125		TData,
126		TError extends string,
127		TRole extends UserRole,
128	>(
129		logicFunction: (
130			input: undefined,
131			context: PrivateServerActionContext<TRole>,
132		) => Promise<Result<TData, TError>>,
133		options: Omit<
134			PrivateOptions<v.UndefinedSchema<undefined>, TData, TError, TRole>,
135			"schema"
136		> & {
137			role: TRole[];
138		},
139	): () => Promise<Result<TData, TError | ServerActionErrorMessage>>;
140	
141	// 5. Private + schema なし + role 指定なし
142	export function createServerAction<TData, TError extends string>(
143		logicFunction: (
144			input: undefined,
145			context: PrivateServerActionContext,
146		) => Promise<Result<TData, TError>>,
147		options: Omit<
148			PrivateOptions<v.UndefinedSchema<undefined>, TData, TError>,
149			"schema"
150		> & {
151			role?: undefined;
152		},
153	): () => Promise<Result<TData, TError | ServerActionErrorMessage>>;
154	
155	// 6. Public + schema なし
156	export function createServerAction<TData, TError extends string>(
157		logicFunction: (
158			input: undefined,
159			context: PublicServerActionContext,
160		) => Promise<Result<TData, TError>>,
161		options: Omit<
162			PublicOptions<v.UndefinedSchema<undefined>, TData, TError>,
163			"schema"
164		>,
165	): () => Promise<Result<TData, TError | ServerActionErrorMessage>>;
166	
167	// 実装
168	export function createServerAction<
169		TSchema extends v.GenericSchema,
170		TData,
171		TError extends string,
172	>(
173		// オーバーロードの実装のため any を許容
174		// eslint-disable-next-line @typescript-eslint/no-explicit-any
175		logicFunction: (input: any, context: any) => Promise<Result<TData, TError>>,
176		options:
177			| PublicOptions<TSchema, TData, TError>
178			| PrivateOptions<TSchema, TData, TError, UserRole>,
179	): (
180		input?: v.InferInput<TSchema>,
181	) => Promise<Result<TData, TError | ServerActionErrorMessage>> {
182		return async (
183			input?: v.InferInput<TSchema>,
184		): Promise<Result<TData, TError | ServerActionErrorMessage>> => {
185			const logger = await getLogger(options.name);
186			logger.info(`${options.name} を実行`, { input });
187	
188			let validatedInput: v.InferOutput<TSchema> =
189				input as v.InferOutput<TSchema>;
190			if (options.schema) {
191				const parseResult = valibot.safeParse(options.schema, input);
192				if (!parseResult.success) {
193					logger.warn("バリデーション失敗", {
194						event: EventType.InputValidationError,
195						issues: parseResult.issues,
196					});
197					return fail(VALIDATION_ERROR_MESSAGE);
198				}
199				validatedInput = parseResult.output;
200			}
201	
202			let context: PublicServerActionContext | PrivateServerActionContext;
203			if (options.isPublic) {
204				context = { logger, role: null, userId: null };
205			} else {
206				const userId = await getUserStaffId();
207				if (!userId) {
208					logger.warn("認証されていないアクセス", {
209						event: EventType.AuthenticationFailure,
210					});
211					return fail(UNAUTHORIZED_ERROR_MESSAGE);
212				}
213	
214				const role = await getUserRole();
215				if (
216					"role" in options &&
217					options.role &&
218					options.role.length > 0 &&
219					!options.role.includes(role)
220				) {
221					logger.warn("権限がないアクセス", {
222						event: EventType.AuthorizationError,
223					});
224					return fail(FORBIDDEN_ERROR_MESSAGE);
225				}
226				context = { logger, role, userId };
227			}
228	
229			try {
230				const result = await logicFunction(validatedInput, context);
231	
232				if (result.success) {
233					logger.info(`${options.name} 成功`);
234					await options.onSuccess?.({
235						input: validatedInput,
236						result: result.data,
237					});
238				} else {
239					logger.warn(`${options.name} 失敗`, { error: result.error });
240					await options.onFailure?.({
241						error: result.error,
242						input: validatedInput,
243					});
244				}
245	
246				return result;
247			} catch (error) {
248				unstable_rethrow(error);
249				logger.error(`${options.name} で予期しないエラーが発生`, { err: error });
250				return fail(INTERNAL_SERVER_ERROR_MESSAGE);
251			}
252		};
253	}

7	 * - サーバーとクライアントで異なる値を安全に扱える設計
8	 * - React 18以降でハイドレーション状態を扱う推奨パターン
9	 * - StrictModeでの安定性が高い
10	 * - 値が変更されない外部状態(ブラウザ環境)の場合、空のsubscribe関数は正当な使用法
11	 */
12	function emptyUnsubscribe(): void {}
13	
14	function subscribe(): () => void {
15		return emptyUnsubscribe;
16	}
17	
18	export function useIsHydrated(): { isHydrated: boolean } {
19		const isHydrated = useSyncExternalStore(
20			// subscribe: 値が変更されないため空の関数を返す
21			subscribe,
22			// getSnapshot: クライアント側では常にtrue
23			() => true,
24			// getServerSnapshot: サーバー側では常にfalse
25			() => false,
26		);
27	
28		return { isHydrated };
29	}

